import React, { useState, useEffect } from 'react';
import { supabase } from './supabase'; // Assure-toi que ce chemin est bon
import ProjectsScreen from './components/ProjectsScreen';

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Vérifier la session active
    const session = supabase.auth.session();
    setUser(session?.user || null);
    setLoading(false);

    // Écouter les changements d'auth
    const { data: authListener } = supabase.auth.onAuthStateChange((event, session) => {
      setUser(session?.user || null);
    });

    return () => {
      authListener?.unsubscribe();
    };
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  // Si pas d'utilisateur, on pourrait afficher un écran de login simple
  // Pour l'instant, on affiche ProjectsScreen même si user est null (il gérera l'affichage)
  // Ou tu peux décommenter la ligne ci-dessous pour forcer un message si pas connecté
  // if (!user) return <div className="p-10 text-center">Veuillez vous connecter via l'interface principale.</div>;

  const handleLoadProject = (id) => {
    console.log("Charger projet:", id);
    // Ici tu mettras ta logique de navigation vers l'éditeur
    alert("Navigation vers le projet " + id + " (à implémenter)");
  };

  const handleNewProject = () => {
    console.log("Nouveau projet");
    alert("Création nouveau projet (à implémenter)");
  };

  return (
    <ProjectsScreen 
      user={user} 
      onLoad={handleLoadProject} 
      onNew={handleNewProject} 
    />
  );
}

export default App;
